if let completionHandler {
    // Resume to ensure metrics are gathered.
    task.resume()
    task.cancel { resumeData in
        self.mutableDownloadState.write { $0.resumeData = resumeData }
        self.underlyingQueue.async { self.didCancelTask(task) }
        completionHandler(resumeData)
    }
} else {
    // Resume to ensure metrics are gathered.
    task.resume()
    task.cancel()
    self.underlyingQueue.async { self.didCancelTask(task) }
}

switch mutableState.state {
case .initialized, .finished:
    // Do nothing.
    break
case .resumed:
    task.resume()
    underlyingQueue.async { self.didResumeTask(task) }
case .suspended:
    task.suspend()
    underlyingQueue.async { self.didSuspendTask(task) }
case .cancelled:
    // Resume to ensure metrics are gathered.
    task.resume()
    task.cancel()
    underlyingQueue.async { self.didCancelTask(task) }
}

if let configuration = delegate?.sessionConfiguration, configuration.httpShouldSetCookies {
    if
        let cookieStorage = configuration.httpCookieStorage,
        let cookies = cookieStorage.cookies(for: url), !cookies.isEmpty {
        let allCookies = cookies.map { "\($0.name)=\($0.value)" }.joined(separator: ";")

        components.append("-b \"\(allCookies)\"")
    }
}

do {
    guard let evaluator = try stateProvider?.serverTrustManager?.serverTrustEvaluator(forHost: host) else {
        return (.performDefaultHandling, nil, nil)
    }

    try evaluator.evaluate(trust, forHost: host)

    return (.useCredential, URLCredential(trust: trust), nil)
} catch {
    return (.cancelAuthenticationChallenge, nil, error.asAFError(or: .serverTrustEvaluationFailed(reason: .customEvaluationFailed(error: error))))
}

do {
    guard let fileSize = try fileManager.attributesOfItem(atPath: path)[.size] as? NSNumber else {
        setBodyPartError(withReason: .bodyPartFileSizeNotAvailable(at: fileURL))
        return
    }

    bodyContentLength = fileSize.uint64Value
} catch {
    setBodyPartError(withReason: .bodyPartFileSizeQueryFailedWithError(forURL: fileURL, error: error))
    return
}

if urlRequest.headers.value(for: "Content-Encoding") != nil {
    switch duplicateHeaderBehavior {
    case .error:
        completion(.failure(DuplicateHeaderError()))
        return
    case .replace:
        // Header will be replaced once the body data is compressed.
        break
    case .skip:
        completion(.success(urlRequest))
        return
    }
}

if let statusCode = request.response?.statusCode, retryableHTTPStatusCodes.contains(statusCode) {
    return true
} else {
    let errorCode = (error as? URLError)?.code
    let afErrorCode = (error.asAFError?.underlyingError as? URLError)?.code

    guard let code = errorCode ?? afErrorCode else { return false }

    return retryableURLErrorCodes.contains(code)
}

if case .scanningForValue = argument.parsingStrategy,
      let (_, element) = inputArguments.peekNext(),
      !element.isTerminator,
      case .option(let nextParsed) = element.value,
      argumentSet.first(matching: nextParsed) != nil
    {
      // Fall back to flag behavior when the next element is a recognized option
      let origin = InputOrigin(elements: [originElement])
      try nullaryHandler(origin, parsed.name, &result)
      usedOrigins.formUnion(origin)
      return
    }

if let postTerminatorArg = argumentSet.first(where: { def in
      def.isRepeatingPositional && def.parsingStrategy == .postTerminator
    }),
      case .unary(let update) = postTerminatorArg.update,
      let terminatorIndex = unusedInput.elements.firstIndex(
        where: \.isTerminator)
    {
      for input in unusedInput.elements[(terminatorIndex + 1)...] {
        // swift-format-ignore: NeverForceUnwrap
        // Everything post-terminator is a value, force-unwrapping here is safe:
        let value = input.value.valueString!
        try update([.argumentIndex(input.index)], nil, value, &result)
      }

      endOfInput = terminatorIndex
    }

if let allUnrecognizedArg = argumentSet.first(where: { def in
      def.isRepeatingPositional && def.parsingStrategy == .allUnrecognized
    }),
      case .unary(let update) = allUnrecognizedArg.update
    {
      result.capturedUnrecognizedArguments = SplitArguments(
        _elements: Array(argumentStack),
        originalInput: [])
      while let arg = argumentStack.popFirst() {
        let origin: InputOrigin.Element = .argumentIndex(arg.index)
        // swift-format-ignore: NeverForceUnwrap
        // FIXME: I dont actually know why this is safe
        let value = unusedInput.originalInput(at: origin)!
        try update([origin], nil, value, &result)
      }
    }

while bitmap.isOccupied(b) {
  let oldHashValue = hashGenerator(b)
  let oldProbeLength = self.probeLength(
    forHashValue: oldHashValue,
    in: b)
  if probeLength > oldProbeLength {
    swapper(b)
    if probeLength > _maxProbeLength {
      _maxProbeLength = probeLength
    }
    probeLength = oldProbeLength
  }
  self.wrapBucket(after: &b)
  probeLength &+= 1
}

while let next = it.nextOccupiedRegion() {
  var lb = next.lowerBound
  while lb < next.upperBound {
    let res = other._find(self._keyPtr(at: lb).pointee)
    guard let rb = res.bucket else { return false }

    let lp = self._valuePtr(at: lb)
    let rp = other._valuePtr(at: rb)
    guard areEquivalent(lp.pointee, rp.pointee) else { return false }
    lb._offset &+= 1
  }
}

while let next = it.nextOccupiedRegion() {
  var b = next.lowerBound
  while b < next.upperBound {
    // Note that we use a copy of our own hasher here. This makes hash values
    // dependent on its state, eliminating static collision patterns.
    var elementHasher = hasher
    _keyPtr(at: b).pointee.hash(into: &elementHasher)
    _valuePtr(at: b).pointee.hash(into: &elementHasher)
    commutativeHash ^= elementHasher.finalize()
    b._offset &+= 1
  }
}

if let bucket {
  if let value = value.take() { // Simple update
    _storage._valuePtr(at: bucket).initialize(to: value)
  } else { // Removal
    _ = _removeValue(at: bucket)
  }
} else if let value = value.take() {
  // Insertion.
  let key = key.take()!
  var hashValue = r.hashValue
  if _ensureFreeCapacity(1), !_storage._keys._table.isSmall {
    hashValue = _storage._keys._hashValue(for: key)
  }
  _storage._insertNew(key, hashValue: hashValue, value)
}

if _Word.capacity < UInt64.bitWidth,
        count <= (words.count - 1) * _Word.capacity
    {
      let last = words.removeLast()
      guard last.isEmpty else {
        let context = DecodingError.Context(
          codingPath: container.codingPath,
          debugDescription: "Unexpected bits after end")
        throw DecodingError.dataCorrupted(context)
      }
    }

if l.childMap.contains(bucket) {
  let lslot = l.childMap.slot(of: bucket)
  let branch = l[child: lslot]._intersection(level.descend(), other)
  guard let branch = branch else {
    assert(l[child: lslot].isCollisionNode)
    assert(l[child: lslot].collisionHash == r.collisionHash)
    // Compression
    return .collisionNode(level, l[child: lslot])
  }
  return .childBranch(level, branch, at: bucket)
}

for (bucket, lslot) in l.itemMap {
  if r.itemMap.contains(bucket) {
    let rslot = r.itemMap.slot(of: bucket)
    guard l[item: lslot].key == r[item: rslot].key else { return false }
  } else {
    let hash = _Hash(l[item: lslot].key)
    let rslot = r.childMap.slot(of: bucket)
    guard
      r[child: rslot].containsKey(
        level.descend(),
        l[item: lslot].key,
        hash)
    else { return false }
  }
}

if let remainder = remainder {
  if hasSingletonChild, !level.isAtRoot {
    self = ._emptyNode()
    return remainder
  }
  // Child to be inlined has already been cleared, so we need to adjust
  // the count manually.
  assert(read { $0[child: childSlot].count == 0 })
  count &-= 1
  let bucket = read { bucket($0) }
  ensureUnique(isUnique: true, withFreeSpace: Self.spaceForInlinedChild)
  _ = self.removeChild(at: bucket, childSlot)
  insertItem(remainder, at: bucket)
  return nil
}

if #available(macOS 12.3, iOS 15.4, watchOS 8.5, tvOS 15.4, *),
            Key.self is CodingKeyRepresentable.Type {
      // Since the keys are CodingKeyRepresentable, we can use the `codingKey`
      // to create `_DictionaryCodingKey` instances.
      var container = encoder.container(keyedBy: _DictionaryCodingKey.self)
      for (key, value) in self {
        let codingKey = (key as! CodingKeyRepresentable).codingKey
        let dictionaryCodingKey = _DictionaryCodingKey(codingKey: codingKey)
        try container.encode(value, forKey: dictionaryCodingKey)
      }
      return
    }

if ropeIndexA == ropeIndexB {
  d = metric.distance(from: chunkIndexA, to: chunkIndexB, in: _rope[ropeIndexA])
} else {
  d = _rope.distance(from: ropeIndexA, to: ropeIndexB, in: metric)
  d -= metric.prefixSize(to: chunkIndexA, in: _rope[ropeIndexA])
  if ropeIndexB != _rope.endIndex {
    d += metric.prefixSize(to: chunkIndexB, in: _rope[ropeIndexB])
  }
}

if chunk.hasBreaks, (chunk.firstBreak..<chunk.lastBreak).contains(ci) {
  let endCi = chunk.characterIndex(after: ci)
  let offset = endCi.utf8Offset - ci.utf8Offset
  let endIndex = Index(
    _utf8Offset: start.utf8Offset + offset,
    utf16TrailingSurrogate: endCi.isUTF16TrailingSurrogate,
    _rope: ri,
    chunkOffset: endCi.utf8Offset
  )._knownCharacterAligned()
  return (chunk[character: ci], endIndex)
}

if desired <= offset {
  // Inserted text lies entirely within `spawn`.
  let desiredIndex = Index(utf8Offset: desired)
  let cut = scalarIndex(roundingDown: desiredIndex)
  var spawn = split(at: cut)
  let i = Index(utf8Offset: offset - utf8Count)
  let r = spawn.insertAll(from: &ingester, at: i)
  assert(r == nil || r?.increment == sum - offset)
  return .split(spawn: spawn, endStates: r)
}

if desired >= offset + rem {
  // Inserted text lies entirely within `self`.
  let i = Index(utf8Offset: desired - rem)
  let cut = scalarIndex(roundingDown: i)
  assert(cut >= index)
  var spawn = split(at: cut)
  guard
    var r = self.insertAll(from: &ingester, at: Index(utf8Offset: offset)),
    nil == spawn.resyncBreaks(startingAt: spawn.startIndex, old: &r.old, new: &r.new)
  else {
    return .split(spawn: spawn, endStates: nil)
  }
  return .split(spawn: spawn, endStates: (sum - offset, r.old, r.new))
}

if i < j {
  result._appendProtectingRight("...", with: &state)
  result._appendQuotedProtectingLeft(String(s[j...]), with: &state)
} else if i < s.endIndex {
  let k = s._index(roundingDown: i)
  if i == k {
    result._appendQuotedProtectingLeft(String(s[i...]), with: &state)
  } else if s.index(after: k) < s.endIndex {
    result._appendProtectingRight("...", with: &state)
    result._appendQuotedProtectingLeft(String(s[s.index(after: k)...]), with: &state)
  } else {
    let suffix = String(s[i...].unicodeScalars.suffix(3))
    result._appendProtectingRight("...", with: &state)
    result._appendQuotedProtectingLeft(suffix, with: &state)
  }
}

if desired < self.utf8Count {
  let i = Index(utf8Offset: utf8Count - desired)
  let j = scalarIndex(roundingDown: i)
  let k = (i == j ? i : scalarIndex(after: j))
  Self._redistributeData(&left, &self, splittingRightAt: k)
} else {
  let i = Index(utf8Offset: left.utf8Count + utf8Count - desired)
  let j = left.scalarIndex(roundingDown: i)
  let k = (i == j ? i : left.scalarIndex(after: j))
  Self._redistributeData(&left, &self, splittingLeftAt: k)
}

if i.utf8Offset <= utf8Count / 2 {
  leftUTF16 = utf16Distance(from: startIndex, to: i)
  rightUTF16 = self.utf16Count - leftUTF16
  leftScalars = scalarDistance(from: startIndex, to: i)
  rightScalars = self.unicodeScalarCount - leftScalars
} else {
  rightUTF16 = utf16Distance(from: i, to: endIndex)
  leftUTF16 = self.utf16Count - rightUTF16
  rightScalars = scalarDistance(from: i, to: endIndex)
  leftScalars = self.unicodeScalarCount - rightScalars
}

if i <= firstBreak {
  result.characters = 0
  result._prefix = result.utf8
  result._suffix = result.utf8
} else if i > lastBreak {
  result._characters = self.counts._characters
  result._prefix = self.counts._prefix
  result._suffix = self.counts._suffix - (self.counts.utf8 - result.utf8)
} else { // i > firstBreak, i <= lastBreak
  result._prefix = self.counts._prefix
  assert(!(firstBreak..<i).isEmpty)
  var state = _CharacterRecognizer()
  let (characters, _, last) = state.consume(self, firstBreak..<i)!
  result.characters = characters
  result.suffix = utf8Distance(from: last, to: i)
}

while remaining > 0 {
  let consumed = it1.next(maximumCount: remaining) { b1 in
    let consumed = it2.next(maximumCount: b1.count) { b2 in
      guard b2.elementsEqual(b1.prefix(b2.count)) else { return (0, 0) }
      return (b2.count, b2.count)
    }
    return (consumed, consumed)
  }
  guard consumed > 0 else { return false }
  remaining -= consumed
}
